### Conditionally Displaying Tabs for VIP Users in Expo Router

Source: https://github.com/expo/expo/blob/main/docs/pages/router/basics/common-navigation-patterns.mdx

This snippet illustrates how to use `Tabs.Protected` within a tabs layout (`(tabs)/_layout.tsx`) to conditionally show or hide specific tabs based on a user's membership status. In this example, the 'vip' tab is only rendered if the user is a VIP member, as determined by the `isVip` state from `useAuthState`.

```tsx
import { Stack } from 'expo-router';
import { useAuthState } from '@/utils/authState';

export default function TabsLayout() {
  const { isVip } = useAuthState();

  return (
    <Tabs>
      <Tabs.Screen name="index" />

      <Tabs.Protected guard={isVip}>
        <Tabs.Screen name="vip" />
      </Tabs.Protected>

      <Tabs.Screen name="settings" />
    </Tabs>
  );
}
```

### Handle Dynamic Routes with Local and Global Params in expo-router

Source: https://context7.com/expo/expo/llms.txt

This snippet shows how to access route parameters for dynamic segments using useLocalSearchParams and useGlobalSearchParams in expo-router.

```tsx
// app/profile/[id].tsx - Dynamic route
import { useLocalSearchParams, useGlobalSearchParams } from 'expo-router';
import { View, Text } from 'react-native';

export default function Profile() {
  // Local params - only updates when this screen is focused
  const { id } = useLocalSearchParams<{ id: string }>();

  // Global params - updates even when not focused
  const globalParams = useGlobalSearchParams();

  return (
    <View>
      <Text>Profile ID: {id}</Text>
    </View>
  );
}
```

